  key: string
  kind: '实体' | '关系'
  name: string
  label: string
  description: string
  count: string
  properties: Array<{ name: string; type: string; required: string; rule: string }>
  mappings: string[]
}

const schemaTypes: SchemaType[] = [
  { key: 'expert', kind: '实体', name: 'Expert', label: '专家 / 人才', description: '标准专家实体，聚合基础信息、教育经历、任职经历和成果证据。', count: '4,286 万', properties: [{ name: 'expert_id', type: 'string', required: '是', rule: '全局唯一' }, { name: 'name', type: 'string', required: '是', rule: '非空，长度 2–100' }, { name: 'aliases', type: 'array<string>', required: '否', rule: '别名归一化' }, { name: 'research_fields', type: 'array<string>', required: '否', rule: '受控词表' }, { name: 'confidence', type: 'decimal', required: '是', rule: '0–1' }], mappings: ['expert_profile', 'expert_education', 'expert_employment'] },
  { key: 'paper', kind: '实体', name: 'Paper', label: '论文成果', description: '论文、会议文章及其作者、机构、引用与主题信息。', count: '2,931 万', properties: [{ name: 'paper_id', type: 'string', required: '是', rule: 'DOI / 标题指纹唯一' }, { name: 'title', type: 'string', required: '是', rule: '非空' }, { name: 'publish_date', type: 'date', required: '否', rule: '不得晚于当前日期' }, { name: 'venue', type: 'string', required: '否', rule: '期刊会议标准化' }], mappings: ['paper_record', 'paper_author_org', 'paper_citation'] },
