  { key: 'project', kind: '实体', name: 'Project', label: '科研项目', description: '科研项目、承担单位、负责人、项目周期和成果。', count: '816 万', properties: [{ name: 'project_id', type: 'string', required: '是', rule: '全局唯一' }, { name: 'project_name', type: 'string', required: '是', rule: '非空' }, { name: 'start_date', type: 'date', required: '否', rule: '早于结束日期' }], mappings: ['project_patent'] },
  { key: 'patent', kind: '实体', name: 'Patent', label: '专利', description: '专利基本信息、发明人、申请人与法律状态。', count: '622 万', properties: [{ name: 'patent_id', type: 'string', required: '是', rule: '申请号唯一' }, { name: 'title', type: 'string', required: '是', rule: '非空' }, { name: 'legal_status', type: 'enum', required: '否', rule: '受控枚举' }], mappings: ['project_patent', 'patent_inventor'] },
  { key: 'coauthor', kind: '关系', name: 'CO_AUTHOR', label: '论文合作', description: '两位专家作为共同作者发表论文形成的事实关系。', count: '0.74 亿', properties: [{ name: 'source', type: 'Expert ID', required: '是', rule: '起点类型 Expert' }, { name: 'target', type: 'Expert ID', required: '是', rule: '终点类型 Expert' }, { name: 'paper_ids', type: 'array<string>', required: '是', rule: '至少 1 条证据' }, { name: 'confidence', type: 'decimal', required: '是', rule: '≥ 0.75 自动入库' }], mappings: ['paper_author_org'] },
  { key: 'worksAt', kind: '关系', name: 'WORKS_AT', label: '任职于', description: '专家在机构的任职关系，包含时间区间、职位和来源证据。', count: '0.68 亿', properties: [{ name: 'source', type: 'Expert ID', required: '是', rule: '起点类型 Expert' }, { name: 'target', type: 'Organization ID', required: '是', rule: '终点类型 Organization' }, { name: 'start_date', type: 'date', required: '否', rule: '时间区间不冲突' }, { name: 'evidence_id', type: 'string', required: '是', rule: '必须可追溯' }], mappings: ['expert_employment'] },
